-- W1.6 questions batch 7398/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00487', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'essay', '員警甲攔查一部行車不穩的車輛，在查驗駕駛乙身分之際，聞到濃濃的
酒氣，要求乙下車配合酒測。當員警甲開啟乙的車門，一望其副駕駛座
下方腳踏墊上方放置手提包一個。在詢問過程中，乙告稱：手提包裡面
的東西，是朋友臨時寄放的雜物。員警甲此時發現其有槍械的前科，試
著請其自行交付該手提包，同時自外部觸摸，並試提該手提包，發現頗
有重量。這時，乙見狀神色緊張、言詞閃爍，拒絕員警甲再度觸碰其手
提包，經員警甲規勸乙自首，乙勉強打開該手提包，員警甲因而查獲包
內改造手槍一把及子彈七顆後，乙坦承該手槍、槍彈為其所持有。
試問：
員警查獲乙手提包內的改造手槍及子彈七顆，是否符合刑事訴訟法的
程序要件？請詳述之。（15 分）
員警查獲之改造手槍及子彈，是否具有證據能力？請詳述之。（5 分）
乙是否符合自首要件？請詳述之。（5 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00488', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'essay', '警方在通訊監聽過程中發現甲、乙兩人有販毒的對話，該通訊監聽的譯
文內容，僅顯示兩人相約見面地點。警察機關於偵訊時，對乙不斷強迫
其承認有向甲購買毒品，但是甲始終否認販毒，並對於乙指證所謂「甲
有販賣『甲基安非他命』毒品給他」的事實，亦加以否認。
案件經移送，檢察官先以施用第二級毒品之被告身分偵訊乙，期間轉換
為證人身分訊問，經告以具結之義務及偽證之處罰並命朗讀結文為具
結，乙指證：有向甲購買毒品，但已經不記得購買何種毒品，應該是「甲
基安非他命」。惟該檢察官並未告知乙得拒絕證言。
試問：
本案檢察官所製作之筆錄，有無證據能力？請詳述之。（15分）
本案偵查人員如何確認該毒品的種類，請至少寫出三種偵查方法？
請詳述之。（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00489', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '告發為偵查開始原因之一，下列敘述何者錯誤？', '["告訴權人以外之第三人知有犯罪嫌疑，而向偵查機關申告犯罪事實促使開始偵查", "公務員因執行職務知有犯罪嫌疑，而向偵查機關申告犯罪事實促使開始偵查", "告發人對於檢察官所為不起訴處分，有權聲請再議", "告發得以書狀或言詞為之，所用之方式與告訴相同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00490', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關警察詢問通知，下列敘述何者錯誤？', '["因調查犯罪嫌疑人犯罪情形及蒐集證據之必要，得使用通知書，通知犯罪嫌疑人到場詢問", "得通知到場之對象，以犯罪嫌疑人為限，不包括犯罪嫌疑人以外之證人", "犯罪嫌疑人經合法通知，無正當理由而不到場者，得報請檢察官核發拘票", "詢問通知書，由司法警察機關主管長官簽名"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00491', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '執行拘提、逮捕及解送，下列敘述何者錯誤？', '["依刑事訴訟法第88條之1第1項規定程序拘提犯罪嫌疑人，應即告知本人及其家屬，得選任 辯護人到場", "執行拘捕，應當場告知犯嫌拘捕原因及刑事訴訟法第95條第1項所列事項，違反告知義務相 對排除其證據能力", "執行拘捕，得使用戒具。使用戒具之範圍、方式、程序及其他應遵行事項之實施辦法，由司法 院會同行政院定之", "拘提或因通緝逮捕之被告，應即解送指定之處所。司法警察官、司法警察逮捕或接受現行犯者， 應即解送檢察官"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00492', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關扣押之執行，下列敘述何者錯誤？', '["司法實務上，司法警察或司法警察官不僅能受命執行扣押，尚有逕以命令扣押之處分權限", "執行搜索或扣押時，發現本案應扣押之物為搜索票或扣押裁定所未記載者，亦得扣押之", "應扣押物之所有人、持有人或保管人無正當理由拒絕提出或交付或抗拒扣押者，得用強制力扣 押之", "依法扣押之物，如私自取回隱匿或予以毀壞，雖不成立竊盜或毀損罪，仍構成妨害公務罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00493', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '受理告發、告訴、自首，下列敘述何者正確？', '["告訴人表示保留告訴權，仍生告訴效力", "就特定犯罪到案自首，但不自白犯罪情節，不生自首效力", "檢察官對於案件緩起訴處分應通知告發人", "告發人得就檢察官不起訴處分聲請再議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00494', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '無證據能力之證據不得作為判斷之依據，下列何者非屬絕對排除之情形？', '["違背刑事訴訟法第100條之3第1項規定所取得犯罪嫌疑人之自白及其他不利之陳述", "以刑求方式取得之陳述", "通訊保障及監察法第18條之1所定不得作為證據或不得採為證據之情形者", "依刑事訴訟法第100條之1第2項規定，筆錄所載被告（含犯罪嫌疑人）之陳述，與同步錄音 或錄影內容不符之部分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00495', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關勘驗之規定，下列敘述何者錯誤？', '["法院、檢察官或司法警察因調查證據及犯罪情形，得實施勘驗", "行勘驗時，得命證人、鑑定人到場", "檢察官實施勘驗，如有必要，得通知當事人、代理人或辯護人到場", "檢查身體，如係對於被告以外之人，以有相當理由可認為於調查犯罪情形有必要者為限，始得 為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00496', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關刑案現場處理，下列敘述何者正確？', '["刑案現場封鎖範圍及層數，應視現場環境及事實需要而定，初期封鎖之範圍應窄", "實施刑案現場封鎖時，應派員於封鎖線內警戒", "於刑案現場逮捕犯罪嫌疑人時，應立即帶離；於刑案現場以外之處所逮捕時，可帶回現場模擬 表演", "刑案現場勘察採證及送驗，應依刑事鑑識手冊、刑案現場數位證物蒐證手冊及爆裂物案件處理 要點等規定辦理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "c797e2a17bd8", "answer_pdf_sha1": "5cf90af717ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1309", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
